cds-views-007.codeExamples:
@AbapCatalog.sqlViewName: 'ZAIRLINE_SEC_V'
@AccessControl.authorizationCheck: #CHECK
@EndUserText.label: 'Airline Data with DCL Security'
define view ZCDS_AIRLINE_SECURE
  as select from scarr
{
  key scarr.carrid   as AirlineID,
      scarr.carrname as AirlineName,
      scarr.currcode as Currency,
      scarr.url      as WebsiteURL
}

" DCL Source: ZCDS_AIRLINE_SECURE (same name)
@MappingRole: true
define role ZCDS_AIRLINE_SECURE {
  grant select on ZCDS_AIRLINE_SECURE
    where (AirlineID)
           = aspect pfcg_auth( S_CARRID,
                               CARRID,
                               ACTVT = '03' );
}

" ABAP usage - automatic authorization filter
SELECT AirlineID, AirlineName
  FROM zcds_airline_secure
  INTO TABLE @DATA(lt_airlines).
" Only user's authorized airlines returned automatically

followupAnswerBank.codeExample:
" Production view - must use #CHECK
@AccessControl.authorizationCheck: #CHECK
define view ZCDS_SALARY_DATA
  as select from pa0008
{ key pa0008.pernr, pa0008.lga01, pa0008.bet01 }

" Development/utility view - no sensitive data
@AccessControl.authorizationCheck: #NOT_REQUIRED
define view ZCDS_CONFIG_PARAMS
  as select from t001
{ key t001.bukrs, t001.butxt }

" RAP internal view - external access blocked
@AccessControl.authorizationCheck: #PRIVILEGED_ONLY
define view entity ZI_DRAFT_ORDER
  as select from zorder_d
{ key zorder_d.orderid, zorder_d.status }

" Step 1: CDS View with #CHECK annotation
@AccessControl.authorizationCheck: #CHECK
define view ZCDS_EMPLOYEE_DATA
  as select from pa0001
{
  key pa0001.pernr as EmployeeID,
      pa0001.orgeh  as OrgUnit,
      pa0001.plans  as Position
}

" Step 2: DCL Source - SAME NAME as CDS view
" Create in ADT: New → Access Control → ZCDS_EMPLOYEE_DATA
@MappingRole: true
define role ZCDS_EMPLOYEE_DATA {
  grant select on ZCDS_EMPLOYEE_DATA
    where (OrgUnit)
           = aspect pfcg_auth( P_ORGIN,
                               ORGEH,
                               INFTY = '0001',
                               ACTVT = '03' );
}

@OData.publish: true
@AccessControl.authorizationCheck: #CHECK
define view ZCDS_SALES_BY_VKORG
  as select from vbak
{
  key vbak.vbeln as SalesOrder,
      vbak.vkorg  as SalesOrg,
      vbak.kunnr  as Customer,
      vbak.netwr  as NetValue
}

" DCL: ZCDS_SALES_BY_VKORG
@MappingRole: true
define role ZCDS_SALES_BY_VKORG {
  grant select on ZCDS_SALES_BY_VKORG
    where (SalesOrg)
           = aspect pfcg_auth( V_VBAK_VKO,
                               VKORG,
                               ACTVT = '03' );
}
" OData: /SalesOrders → auto-filtered by user's VKORG auth
